import React, { useEffect, useState, useCallback, useRef } from 'react';
import {
  Card,
  Button,
  dispatchAppToast,
} from '@linm-soft-org/linm-web-common-components';
import {
  Title,
  Text,
  Tag,
  Modal,
  Popconfirm,
  Tooltip,
  Space,
  Spin,
} from '@/components/common';
import { fpcService } from '../../../services/fpc/service';
import type { ScenarioResultDto, CreateScenarioDto, CostCodeDto } from '../../../services/fpc/types';
import { useAppDispatch } from '../../../store/hooks';
import styles from './ScenarioManagerPage.module.css';

const SCENARIO_COLORS: Record<string, string> = {
  Base: 'blue',
  Downside: 'red',
  Upside: 'green',
  Expansion: 'purple',
  Stress: 'orange',
  Custom: 'geekblue',
};

const SCENARIO_LABELS: Record<string, string> = {
  Base: 'Kịch bản cơ sở',
  Downside: 'Kịch bản thận trọng',
  Upside: 'Kịch bản tăng trưởng',
  Expansion: 'Mở rộng',
  Stress: 'Căng thẳng',
  Custom: 'Tùy chỉnh',
};

const STATUS_COLORS: Record<string, string> = {
  Draft: 'default',
  Running: 'processing',
  Completed: 'success',
  Failed: 'error',
};

const STATUS_LABELS: Record<string, string> = {
  Draft: 'Bản nháp',
  Running: 'Đang chạy',
  Completed: 'Hoàn thành',
  Failed: 'Thất bại',
};

export default function ScenarioManagerPage() {
  const dispatch = useAppDispatch();
  const [data, setData] = useState<ScenarioResultDto[]>([]);
  const [costCodes, setCostCodes] = useState<CostCodeDto[]>([]);
  const [loading, setLoading] = useState(true);
  const [modalOpen, setModalOpen] = useState(false);
  const [creating, setCreating] = useState(false);
  const [viewModalOpen, setViewModalOpen] = useState(false);
  const [viewItem, setViewItem] = useState<ScenarioResultDto | null>(null);

  // Create form refs
  const nameRef = useRef<HTMLInputElement>(null);
  const scenarioTypeRef = useRef<HTMLSelectElement>(null);
  const periodStartRef = useRef<HTMLInputElement>(null);
  const periodEndRef = useRef<HTMLInputElement>(null);
  const totalBudgetRef = useRef<HTMLInputElement>(null);
  const summaryRef = useRef<HTMLTextAreaElement>(null);

  // Cost items in create modal
  const [costItemEntries, setCostItemEntries] = useState<Record<string, string>>({});

  const fetchData = useCallback(async () => {
    setLoading(true);
    try {
      const [result, codes] = await Promise.all([
        fpcService.getScenarioList(),
        fpcService.getCostCodeList(),
      ]);
      setData(result);
      setCostCodes(codes);
    } finally {
      setLoading(false);
    }
  }, []);

  useEffect(() => {
    fetchData();
  }, [fetchData]);

  const handleCreate = () => {
    if (nameRef.current) nameRef.current.value = '';
    if (scenarioTypeRef.current) scenarioTypeRef.current.value = 'Base';
    if (periodStartRef.current) periodStartRef.current.value = '';
    if (periodEndRef.current) periodEndRef.current.value = '';
    if (totalBudgetRef.current) totalBudgetRef.current.value = '';
    if (summaryRef.current) summaryRef.current.value = '';
    setCostItemEntries({});
    setModalOpen(true);
  };

  const handleCostItemChange = (costCode: string, value: string) => {
    setCostItemEntries((prev) => ({ ...prev, [costCode]: value }));
  };

  const handleSubmit = async () => {
    if (!nameRef.current?.value) return;
    if (!periodStartRef.current?.value || !periodEndRef.current?.value) return;

    setCreating(true);
    try {
      const costItems = Object.entries(costItemEntries)
        .filter(([_, val]) => val && parseFloat(val) > 0)
        .map(([code, val]) => {
          const cc = costCodes.find((c) => c.code === code);
          return {
            costCode: code,
            costCodeName: cc?.name || code,
            amount: parseFloat(val),
          };
        });

      const dto: CreateScenarioDto = {
        name: nameRef.current.value,
        scenarioType: scenarioTypeRef.current?.value || 'Base',
        periodStart: new Date(periodStartRef.current.value).toISOString(),
        periodEnd: new Date(periodEndRef.current.value).toISOString(),
        totalBudget: totalBudgetRef.current?.value ? parseFloat(totalBudgetRef.current.value) : undefined,
        summary: summaryRef.current?.value,
        assumptionsJson: undefined,
        costItems: costItems.length > 0 ? costItems : undefined,
      };
      await fpcService.createScenario(dto);
      dispatchAppToast(dispatch, { message: 'Đã tạo kịch bản', type: 'success' });
      setModalOpen(false);
      fetchData();
    } finally {
      setCreating(false);
    }
  };

  const handleRun = async (id: string) => {
    await fpcService.runScenario(id);
    dispatchAppToast(dispatch, { message: 'Đã chạy kịch bản', type: 'success' });
    fetchData();
  };

  const handleDelete = async (id: string) => {
    await fpcService.deleteScenario(id);
    dispatchAppToast(dispatch, { message: 'Đã xóa kịch bản', type: 'success' });
    fetchData();
  };

  const handleView = (record: ScenarioResultDto) => {
    setViewItem(record);
    setViewModalOpen(true);
  };

  const formatMoney = (v?: number) =>
    v !== undefined
      ? new Intl.NumberFormat('vi-VN', { style: 'currency', currency: 'VND' }).format(v)
      : '-';

  const renderTableRows = () => {
    if (loading) {
      return (
        <tr>
          <td colSpan={9} style={{ textAlign: 'center', padding: 24 }}>
            <Spin />
          </td>
        </tr>
      );
    }
    if (data.length === 0) {
      return (
        <tr>
          <td colSpan={9} style={{ textAlign: 'center', padding: 24, color: '#999' }}>
            Chưa có kịch bản nào
          </td>
        </tr>
      );
    }
    return data.map((record) => (
      <tr key={record.id}>
        <td className={styles.cellName}>{record.name}</td>
        <td className={styles.cellType}>
          <Tag color={SCENARIO_COLORS[record.scenarioType] || 'default'}>{SCENARIO_LABELS[record.scenarioType] || record.scenarioType}</Tag>
        </td>
        <td className={styles.cellStatus}>
          <Tag color={STATUS_COLORS[record.status] || 'default'}>{STATUS_LABELS[record.status] || record.status}</Tag>
        </td>
        <td className={styles.cellRight}>{formatMoney(record.totalBudget)}</td>
        <td className={styles.cellRight}>{formatMoney(record.projectedRevenue)}</td>
        <td className={styles.cellRight}>
          <Text type={record.projectedEbitda && record.projectedEbitda >= 0 ? 'success' : 'danger'}>
            {formatMoney(record.projectedEbitda)}
          </Text>
        </td>
        <td className={styles.cellRight}>
          <Text type="danger">{formatMoney(record.fundingRequired)}</Text>
        </td>
        <td className={styles.cellSummary}>{record.summary}</td>
        <td className={styles.cellActions}>
          <Space>
            <Tooltip title="Xem kết quả">
              <button className={styles.linkBtn} onClick={() => handleView(record)}>
                <i className="fas fa-eye" />
              </button>
            </Tooltip>
            {record.status !== 'Running' && (
              <Tooltip title="Chạy kịch bản">
                <button className={styles.linkBtn} onClick={() => handleRun(record.id)}>
                  <i className="fas fa-play-circle" />
                </button>
              </Tooltip>
            )}
            <Popconfirm title="Xóa kịch bản?" onConfirm={() => handleDelete(record.id)}>
              <button className={styles.linkBtn} style={{ color: 'red' }}>
                <i className="fas fa-trash" />
              </button>
            </Popconfirm>
          </Space>
        </td>
      </tr>
    ));
  };

  const renderCostItemRows = () => {
    if (!viewItem?.costItems || viewItem.costItems.length === 0) return null;
    return (
      <div style={{ marginTop: 16 }}>
        <Text strong style={{ fontSize: 14, display: 'block', marginBottom: 8 }}>
          Chi tiết khoản mục chi phí
        </Text>
        <table className={styles.table} style={{ fontSize: 12 }}>
          <thead>
            <tr>
              <th style={{ textAlign: 'left', padding: '6px 10px' }}>Mã CP</th>
              <th style={{ textAlign: 'left', padding: '6px 10px' }}>Tên chi phí</th>
              <th style={{ textAlign: 'right', padding: '6px 10px' }}>Số tiền</th>
              <th style={{ textAlign: 'left', padding: '6px 10px' }}>Ghi chú</th>
            </tr>
          </thead>
          <tbody>
            {viewItem.costItems.map((ci) => (
              <tr key={ci.id}>
                <td style={{ padding: '6px 10px' }}><Text strong>{ci.costCode}</Text></td>
                <td style={{ padding: '6px 10px' }}>{ci.costCodeName}</td>
                <td style={{ padding: '6px 10px', textAlign: 'right' }}>{formatMoney(ci.amount)}</td>
                <td style={{ padding: '6px 10px' }}>{ci.note || '-'}</td>
              </tr>
            ))}
          </tbody>
        </table>
      </div>
    );
  };

  const totalCostItemAmount = Object.values(costItemEntries)
    .reduce((sum, v) => sum + (parseFloat(v) || 0), 0);

  return (
    <div className={styles.page}>
      <Title>Quản lý Kịch bản</Title>

      <Card style={{ marginBottom: 16 }}>
        <Button variant="primary" onClick={handleCreate}>
          <i className="fas fa-plus" style={{ marginRight: 6 }} />
          Tạo kịch bản mới
        </Button>
      </Card>

      <table className={styles.table}>
        <thead>
          <tr>
            <th className={styles.thName}>Tên</th>
            <th className={styles.thType}>Loại</th>
            <th className={styles.thStatus}>Trạng thái</th>
            <th className={styles.thRight}>Tổng dự chi</th>
            <th className={styles.thRight}>Doanh thu dự kiến</th>
            <th className={styles.thRight}>Lợi nhuận trước khấu hao</th>
            <th className={styles.thRight}>Vốn cần</th>
            <th className={styles.thSummary}>Tóm tắt</th>
            <th className={styles.thActions}></th>
          </tr>
        </thead>
        <tbody>
          {renderTableRows()}
        </tbody>
      </table>

      {/* Create Modal */}
      <Modal
        title="Tạo kịch bản mới"
        open={modalOpen}
        onOk={handleSubmit}
        onCancel={() => setModalOpen(false)}
        width={700}
        confirmLoading={creating}
      >
        <div className={styles.formFields}>
          <div className={styles.fieldRow}>
            <label className={styles.fieldLabel}>
              Tên kịch bản <span className={styles.required}>*</span>
            </label>
            <input
              ref={nameRef}
              className={styles.fieldInput}
              placeholder="VD: Kịch bản thận trọng Q3"
              required
            />
          </div>
          <div className={styles.fieldRow}>
            <label className={styles.fieldLabel}>Loại kịch bản</label>
            <select ref={scenarioTypeRef} className={styles.fieldSelect} defaultValue="Base">
              <option value="Base">Base</option>
              <option value="Downside">Downside</option>
              <option value="Upside">Upside</option>
              <option value="Expansion">Expansion</option>
              <option value="Stress">Stress</option>
              <option value="Custom">Custom</option>
            </select>
          </div>
          <div className={styles.fieldRow}>
            <label className={styles.fieldLabel}>
              Kỳ kế hoạch <span className={styles.required}>*</span>
            </label>
            <div className={styles.dateRangeRow}>
              <input ref={periodStartRef} type="date" className={styles.fieldInput} required />
              <span className={styles.dateSep}>&rarr;</span>
              <input ref={periodEndRef} type="date" className={styles.fieldInput} required />
            </div>
          </div>
          <div className={styles.fieldRow}>
            <label className={styles.fieldLabel}>Tổng số tiền dự chi</label>
            <input
              ref={totalBudgetRef}
              type="number"
              className={styles.fieldInput}
              placeholder="VD: 500000000"
            />
          </div>
          <div className={styles.fieldRow}>
            <label className={styles.fieldLabel}>
              Chi tiết khoản mục chi phí
            </label>
            {costCodes.length > 0 ? (
              <div style={{ maxHeight: 200, overflowY: 'auto', border: '1px solid #f0f0f0', borderRadius: 6, padding: 8 }}>
                {costCodes.filter((cc) => cc.isActive).map((cc) => (
                  <div key={cc.id} style={{ display: 'flex', alignItems: 'center', gap: 8, marginBottom: 6 }}>
                    <span style={{ width: 80, fontSize: 13, fontWeight: 500 }}>{cc.code}</span>
                    <span style={{ flex: 1, fontSize: 13, color: '#666' }}>{cc.name}</span>
                    <input
                      type="number"
                      value={costItemEntries[cc.code] ?? ''}
                      onChange={(e) => handleCostItemChange(cc.code, e.target.value)}
                      placeholder="0"
                      style={{
                        width: 140,
                        height: 30,
                        padding: '2px 8px',
                        border: '1px solid #d9d9d9',
                        borderRadius: 4,
                        fontSize: 13,
                        textAlign: 'right',
                        outline: 'none',
                        boxSizing: 'border-box',
                      }}
                    />
                  </div>
                ))}
                <div style={{ textAlign: 'right', marginTop: 8, fontSize: 13, color: '#888' }}>
                  Tổng: {formatMoney(totalCostItemAmount)}
                </div>
              </div>
            ) : (
              <Text type="secondary">Chưa có mã chi phí. Vui lòng khai báo trước.</Text>
            )}
          </div>
          <div className={styles.fieldRow}>
            <label className={styles.fieldLabel}>Mô tả</label>
            <textarea ref={summaryRef} className={styles.fieldTextarea} rows={2} />
          </div>
        </div>
      </Modal>

      {/* View Result Modal */}
      <Modal
        title={viewItem?.name ?? 'Kết quả kịch bản'}
        open={viewModalOpen}
        onCancel={() => setViewModalOpen(false)}
        footer={null}
        width={750}
      >
        {viewItem && (
          <>
            <p>
              <Text strong>Loại:</Text>{' '}
              <Tag color={SCENARIO_COLORS[viewItem.scenarioType]}>{viewItem.scenarioType}</Tag>
            </p>
            <p>
              <Text strong>Trạng thái:</Text>{' '}
              <Tag color={STATUS_COLORS[viewItem.status]}>{STATUS_LABELS[viewItem.status] || viewItem.status}</Tag>
            </p>
            <p>
              <Text strong>Tổng dự chi:</Text> {formatMoney(viewItem.totalBudget)}
            </p>
            {viewItem.status === 'Completed' && (
              <>
                <p>
                  <Text strong>Doanh thu dự kiến:</Text> {formatMoney(viewItem.projectedRevenue)}
                </p>
                <p>
                  <Text strong>Lợi nhuận trước khấu hao:</Text>{' '}
                  <Text type={viewItem.projectedEbitda && viewItem.projectedEbitda >= 0 ? 'success' : 'danger'}>
                    {formatMoney(viewItem.projectedEbitda)}
                  </Text>
                </p>
                <p>
                  <Text strong>Tiền mặt dự kiến:</Text> {formatMoney(viewItem.projectedCashBalance)}
                </p>
                <p>
                  <Text strong>Vốn cần bổ sung:</Text>{' '}
                  <Text type="danger">{formatMoney(viewItem.fundingRequired)}</Text>
                </p>
                <p>
                  <Text strong>Tóm tắt:</Text> {viewItem.summary}
                </p>
              </>
            )}
            {renderCostItemRows()}
            {viewItem.status === 'Failed' && (
              <p>
                <Text type="danger">Lỗi: {viewItem.errorMessage}</Text>
              </p>
            )}
          </>
        )}
      </Modal>
    </div>
  );
}
